diff --git a/src/Carbon/Traits/Comparison.php b/src/Carbon/Traits/Comparison.php
index 53e54de..18fa17b 100644
--- a/src/Carbon/Traits/Comparison.php
+++ b/src/Carbon/Traits/Comparison.php
@@ -558,7 +558,25 @@ trait Comparison
     public function isSameAs(string $format, DateTimeInterface|string $date): bool
     {
-        return $this->rawFormat($format) === $this->resolveCarbon($date)->rawFormat($format);
+        $other = $this->resolveCarbon($date);
+
+        if (
+            preg_match('/[GgHhisua]/', $format) &&
+            !preg_match('/[POTZe]/', $format) &&
+            $this->getOffset() !== $other->getOffset()
+        ) {
+            $tz = $this->getTimezone();
+            $self = $this->avoidMutation()->setTimezone($tz);
+            $normalizedOther = $other->avoidMutation()->setTimezone($tz);
+            return $self->rawFormat($format) === $normalizedOther->rawFormat($format);
+        }
+
+        return $this->rawFormat($format) === $other->rawFormat($format);
     }
